  const isOneToMany = field.isList  // Array of related items
  const isManyToOne = !field.isList // Single related item
  const relationName = field.relationName
  const foreignKeyFields = field.relationFromFields  // Which local fields are the FK
  const referencedFields = field.relationToFields    // Which remote fields are referenced
}

