## 8. KEY PATTERNS FOR REST API GENERATOR

```typescript
import { generatorHandler } from '@prisma/generator-helper'
import type { GeneratorOptions, DMMF } from '@prisma/generator'
import * as ts from '@prisma/ts-builders'
import fs from 'node:fs/promises'
import path from 'node:path'

generatorHandler({
  async onManifest() {
    return {
      prettyName: 'REST API Client Generator',
      defaultOutput: '../src/generated',
    }
  },

  async onGenerate(options: GeneratorOptions) {
    const outputDir = options.generator.output?.value || './generated'

    // 1. Iterate models
    for (const model of options.dmmf.datamodel.models) {
      // 2. Create REST types for each model
      const tsInterface = createModelInterface(model, options.dmmf)

      // 3. Create request/response types for each operation
      const createRequestType = createRequestType('Create', model)
      const updateRequestType = createRequestType('Update', model)

      // 4. Generate endpoint handlers/clients
      const routeFile = generateRouteFile(model, options.dmmf)

      // 5. Write files
      await fs.writeFile(
        path.join(outputDir, `${model.name}.ts`),
        routeFile
      )
    }

    // 6. Generate index file exporting all types
    const indexFile = generateIndexFile(options.dmmf.datamodel.models)
    await fs.writeFile(path.join(outputDir, 'index.ts'), indexFile)
  }
})

function createModelInterface(model: DMMF.Model, dmmf: DMMF.Document): ts.Interface {
  const iface = ts.interfaceDeclaration(model.name)

  for (const field of model.fields) {
    if (field.kind === 'object') continue  // Skip relations for basic interface

    const fieldType = getTypeScriptType(field)
    const prop = ts.property(field.name, fieldType)

    if (!field.isRequired) {
      prop.optional()
    }

    iface.add(prop)
  }

  return iface
}

function getTypeScriptType(field: DMMF.Field): ts.TypeBuilder {
  const typeMap: Record<string, string> = {
    String: 'string',
    Int: 'number',
    Float: 'number',
    Boolean: 'boolean',
    DateTime: 'Date',
    Json: 'Record<string, any>',
  }

  let type = ts.namedType(typeMap[field.type] || field.type)

  if (field.isList) {
    type = ts.array(type)
  }

  return type
}
```

