import type { Field, Model, ModelMapping } from '@prisma/dmmf'
import {
  array,
  interfaceDeclaration,
  moduleExport,
  namedType,
  nullType,
  property,
  stringify,
  TypeBuilder,
  unionType,
  unknownType,
} from '@prisma/ts-builders'

import { mapScalarToTsType } from './field-type-mapper'

export type ModelBuildResult = {
  /** Model interface + all four input type interfaces as a single joined string. */
  typeDeclarations: string
  /** The `interface {Model}Delegate` method signature block. */
  delegateInterface: string
  /** The `class {Model}Delegate` with fetch-based CRUD implementations. */
  delegateImpl: string
}

// ---------------------------------------------------------------------------
// Field type helpers
// ---------------------------------------------------------------------------

function getBaseFieldTsType(field: Field): TypeBuilder {
  if (field.kind === 'scalar') {
    return namedType(mapScalarToTsType(field.type))
  }
  if (field.kind === 'enum') {
    return namedType(field.type)
  }
  return unknownType
}

function getFieldTsType(field: Field): TypeBuilder {
  let type: TypeBuilder = getBaseFieldTsType(field)
  if (field.isList) {
    type = array(type)
  }
  if (!field.isRequired) {
    type = unionType([type, nullType])
  }
  return type
}

// ---------------------------------------------------------------------------
// CreateInput / UpdateInput field filters
// ---------------------------------------------------------------------------

function isAutoGeneratedField(field: Field): boolean {
  return field.isId && field.hasDefaultValue
}

function isCreateInputField(field: Field): boolean {
  if (field.kind === 'object' || field.kind === 'unsupported') return false
  if (field.isUpdatedAt) return false
  if (isAutoGeneratedField(field)) return false
  if (field.isReadOnly) return false
  return true
}

function isUpdateInputField(field: Field): boolean {
  if (!isCreateInputField(field)) return false
  // The primary key belongs in `where`, not `data`.
  if (field.isId) return false
  return true
}

// ---------------------------------------------------------------------------
// Interface builders
// ---------------------------------------------------------------------------

function buildModelInterface(model: Model): string {
  const iface = interfaceDeclaration(model.name)
  for (const field of model.fields) {
    if (field.kind === 'object' || field.kind === 'unsupported') continue
    iface.add(property(field.name, getFieldTsType(field)))
  }
  return stringify(moduleExport(iface), { newLine: 'trailing' })
}

function buildWhereUniqueInput(model: Model): string {
  const iface = interfaceDeclaration(`${model.name}WhereUniqueInput`)
  for (const field of model.fields) {
    if (field.kind === 'object' || field.kind === 'unsupported') continue
    if (!field.isId && !field.isUnique) continue
    // Nullable identifiers don't make sense as lookup keys; use the base type.
    iface.add(property(field.name, getBaseFieldTsType(field)).optional())
  }
  return stringify(moduleExport(iface), { newLine: 'trailing' })
}

function buildWhereInput(model: Model): string {
  const iface = interfaceDeclaration(`${model.name}WhereInput`)
  for (const field of model.fields) {
    if (field.kind === 'object' || field.kind === 'unsupported') continue
    iface.add(property(field.name, getFieldTsType(field)).optional())
  }
  return stringify(moduleExport(iface), { newLine: 'trailing' })
}

function buildCreateInput(model: Model): string {
  const iface = interfaceDeclaration(`${model.name}CreateInput`)
  for (const field of model.fields) {
    if (!isCreateInputField(field)) continue
    const type = getFieldTsType(field)
    const isRequiredField = field.isRequired && !field.hasDefaultValue && !field.isList
    const prop = property(field.name, type)
    if (!isRequiredField) {
      prop.optional()
    }
    iface.add(prop)
  }
  return stringify(moduleExport(iface), { newLine: 'trailing' })
}

function buildUpdateInput(model: Model): string {
  const iface = interfaceDeclaration(`${model.name}UpdateInput`)
  for (const field of model.fields) {
    if (!isUpdateInputField(field)) continue
    iface.add(property(field.name, getFieldTsType(field)).optional())
  }
  return stringify(moduleExport(iface), { newLine: 'trailing' })
}

// ---------------------------------------------------------------------------
// Delegate interface (method signatures only)
// ---------------------------------------------------------------------------

function buildDelegateInterface(modelName: string): string {
  return [
    `interface ${modelName}Delegate {`,
    `  findMany(args?: { skip?: number; take?: number; where?: ${modelName}WhereInput }): Promise<${modelName}[]>`,
    `  findUnique(args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName} | null>`,
    `  create(args: { data: ${modelName}CreateInput }): Promise<${modelName}>`,
    `  update(args: { where: ${modelName}WhereUniqueInput; data: ${modelName}UpdateInput }): Promise<${modelName}>`,
    `  delete(args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName}>`,
    `}`,
    ``,
  ].join('\n')
}

// ---------------------------------------------------------------------------
// Delegate implementation (fetch-based)
// ---------------------------------------------------------------------------

function buildDelegateImpl(modelName: string, pluralName: string): string {
  return [
    `class ${modelName}Delegate implements ${modelName}Delegate {`,
    `  constructor(private baseUrl: string) {}`,
    ``,
    `  async findMany(args?: { skip?: number; take?: number; where?: ${modelName}WhereInput }): Promise<${modelName}[]> {`,
    `    const params = new URLSearchParams()`,
    `    if (args?.skip !== undefined) params.set('skip', String(args.skip))`,
    `    if (args?.take !== undefined) params.set('take', String(args.take))`,
    `    if (args?.where !== undefined) params.set('where', JSON.stringify(args.where))`,
    `    const query = params.toString().length > 0 ? '?' + params.toString() : ''`,
    `    const res = await fetch(\`\${this.baseUrl}/${pluralName}\${query}\`)`,
    `    if (!res.ok) throw new Error(\`findMany ${pluralName} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}[]>`,
    `  }`,
    ``,
    `  async findUnique(args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName} | null> {`,
    `    const params = new URLSearchParams({ where: JSON.stringify(args.where) })`,
    `    const res = await fetch(\`\${this.baseUrl}/${pluralName}/unique?\${params}\`)`,
    `    if (res.status === 404) return null`,
    `    if (!res.ok) throw new Error(\`findUnique ${pluralName} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    ``,
    `  async create(args: { data: ${modelName}CreateInput }): Promise<${modelName}> {`,
    `    const res = await fetch(\`\${this.baseUrl}/${pluralName}\`, {`,
    `      method: 'POST',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(args.data),`,
    `    })`,
    `    if (!res.ok) throw new Error(\`create ${pluralName} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    ``,
    `  async update(args: { where: ${modelName}WhereUniqueInput; data: ${modelName}UpdateInput }): Promise<${modelName}> {`,
    `    const params = new URLSearchParams({ where: JSON.stringify(args.where) })`,
    `    const res = await fetch(\`\${this.baseUrl}/${pluralName}/unique?\${params}\`, {`,
    `      method: 'PUT',`,
    `      headers: { 'Content-Type': 'application/json' },`,
    `      body: JSON.stringify(args.data),`,
    `    })`,
    `    if (!res.ok) throw new Error(\`update ${pluralName} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    ``,
    `  async delete(args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName}> {`,
    `    const params = new URLSearchParams({ where: JSON.stringify(args.where) })`,
    `    const res = await fetch(\`\${this.baseUrl}/${pluralName}/unique?\${params}\`, {`,
    `      method: 'DELETE',`,
    `    })`,
    `    if (!res.ok) throw new Error(\`delete ${pluralName} failed: \${res.status}\`)`,
    `    return res.json() as Promise<${modelName}>`,
    `  }`,
    `}`,
    ``,
  ].join('\n')
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export function buildModel(model: Model, mapping: ModelMapping): ModelBuildResult {
  const typeDeclarations = [
    buildModelInterface(model),
    buildWhereUniqueInput(model),
    buildWhereInput(model),
    buildCreateInput(model),
    buildUpdateInput(model),
  ].join('\n')

  return {
    typeDeclarations,
    delegateInterface: buildDelegateInterface(model.name),
    delegateImpl: buildDelegateImpl(model.name, mapping.plural),
  }
}

