    `  constructor(baseUrl: string = 'http://localhost:3000') {`,
    inits,
    `  }`,
    `}`,
    ``,
  ].join('\n')
}

export async function generateClient(options: GenerateClientOptions): Promise<void> {
  const { outputDir, dmmf } = options
  const { models, enums } = dmmf.datamodel
  const { modelOperations } = dmmf.mappings

  // ---- enums ---------------------------------------------------------------
  const enumSection = enums.map(buildEnumType).join('\n')

  // ---- per-model sections --------------------------------------------------
  const typeDeclarationParts: string[] = []
  const delegateInterfaceParts: string[] = []
  const delegateImplParts: string[] = []
  const modelNames: string[] = []

  for (const model of models) {
    const mapping = modelOperations.find((m) => m.model === model.name)
    if (!mapping) continue

    const result = buildModel(model, mapping)
    typeDeclarationParts.push(result.typeDeclarations)
    delegateInterfaceParts.push(result.delegateInterface)
    delegateImplParts.push(result.delegateImpl)
    modelNames.push(model.name)
  }

  // ---- assemble the file ---------------------------------------------------
  const sections: string[] = [
    FILE_HEADER,
    ...(enumSection ? [enumSection] : []),
    typeDeclarationParts.join('\n'),
    delegateInterfaceParts.join('\n'),
    delegateImplParts.join('\n'),
    buildRestApiClientClass(modelNames),
  ]

  const content = sections.filter(Boolean).join('\n')

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'index.ts'), content, 'utf-8')
}

