    expect(createInputBlock).not.toContain('updatedAt')
    // Relation field should be excluded
    expect(createInputBlock).not.toContain('posts')
  })

  test('UserUpdateInput excludes id field and makes remaining fields optional', async () => {
    await generateClient({ outputDir, dmmf: mockDmmf })

    const content = await fs.readFile(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(content).toContain('export interface UserUpdateInput {')

    const updateInputStart = content.indexOf('export interface UserUpdateInput {')
    const updateInputEnd = content.indexOf('\n}', updateInputStart) + 2
    const updateInputBlock = content.slice(updateInputStart, updateInputEnd)

    expect(updateInputBlock).not.toContain('id:')
    // Fields in UpdateInput should be optional (contain `?:`)
    expect(updateInputBlock).toContain('?:')
  })

