    await generateClient({ outputDir, dmmf: mockDmmf })

    const content = await fs.readFile(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(content).toContain('export interface UserWhereUniqueInput {')

    const whereUniqueStart = content.indexOf('export interface UserWhereUniqueInput {')
    const whereUniqueEnd = content.indexOf('\n}', whereUniqueStart) + 2
    const whereUniqueBlock = content.slice(whereUniqueStart, whereUniqueEnd)

    expect(whereUniqueBlock).toContain('id')
  })

  test('generated file contains exported RestApiClient class with user property', async () => {
    await generateClient({ outputDir, dmmf: mockDmmf })

    const content = await fs.readFile(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(content).toContain('export class RestApiClient {')
    expect(content).toContain('readonly user: UserDelegate')
  })

  test('generated file contains UserDelegate with all five CRUD methods', async () => {
    await generateClient({ outputDir, dmmf: mockDmmf })

    const content = await fs.readFile(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(content).toContain('UserDelegate')
    expect(content).toContain('findMany')
    expect(content).toContain('findUnique')
    expect(content).toContain('create')
    expect(content).toContain('update')
    expect(content).toContain('delete')
  })

  test('generated file contains fetch calls targeting the plural resource path', async () => {
    await generateClient({ outputDir, dmmf: mockDmmf })

    const content = await fs.readFile(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(content).toContain('/users')
  })

  test('generated file starts with the generator header comment', async () => {
    await generateClient({ outputDir, dmmf: mockDmmf })

    const content = await fs.readFile(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(content).toContain('@prisma/rest-api-client-generator')
  })
})

